const tables = [
  {
    name: 'Notes',
    description: 'AI Assistant notes (migrated from Notion)',
    fields: [
      { name: 'Name', type: 'singleLineText' },
      { name: 'Content', type: 'multilineText' },
      { name: 'Type', type: 'singleSelect', options: { choices: [ { name: 'note' }, { name: 'idea' }, { name: 'reminder' }, { name: 'other' } ] } },
      { name: 'Created', type: 'dateTime', options: { dateFormat: { name: 'iso' }, timeFormat: { name: '24hour' }, timeZone: 'client' } }
    ]
  },
  {
    name: 'Transactions',
    description: 'AI Assistant finance transactions (migrated from Google Sheets)',
    fields: [
      { name: 'Date', type: 'date', options: { dateFormat: { name: 'iso' } } },
      { name: 'Type', type: 'singleSelect', options: { choices: [ { name: 'income' }, { name: 'expense' } ] } },
      { name: 'Category', type: 'singleLineText' },
      { name: 'Amount', type: 'number', options: { precision: 2 } },
      { name: 'Currency', type: 'singleSelect', options: { choices: [ { name: 'UAH' }, { name: 'USD' }, { name: 'EUR' } ] } },
      { name: 'Description', type: 'multilineText' },
      { name: 'Source', type: 'singleLineText' },
      { name: 'Created At', type: 'dateTime', options: { dateFormat: { name: 'iso' }, timeFormat: { name: '24hour' }, timeZone: 'client' } }
    ]
  },
  {
    name: 'Recurring Payments',
    description: 'Recurring payments (migrated from Google Sheets)',
    fields: [
      { name: 'Name', type: 'singleLineText' },
      { name: 'Amount', type: 'number', options: { precision: 2 } },
      { name: 'Day', type: 'number', options: { precision: 0 } },
      { name: 'Category', type: 'singleLineText' },
      { name: 'Reminder Days', type: 'number', options: { precision: 0 } },
      { name: 'Active', type: 'checkbox', options: { icon: 'check', color: 'greenBright' } }
    ]
  },
  {
    name: 'Meetings',
    description: 'Pending meeting confirmations (migrated from n8n Data Table)',
    fields: [
      { name: 'title', type: 'singleLineText' },
      { name: 'chat_id', type: 'singleLineText' },
      { name: 'action_type', type: 'singleLineText' },
      { name: 'description', type: 'multilineText' },
      { name: 'date', type: 'singleLineText' },
      { name: 'time', type: 'singleLineText' },
      { name: 'end_time', type: 'singleLineText' },
      { name: 'priority', type: 'singleSelect', options: { choices: [ { name: 'Low' }, { name: 'Medium' }, { name: 'High' } ] } },
      { name: 'status', type: 'singleSelect', options: { choices: [ { name: 'pending' }, { name: 'completed' }, { name: 'cancelled' }, { name: 'expired' } ] } },
      { name: 'created_at', type: 'dateTime', options: { dateFormat: { name: 'iso' }, timeFormat: { name: '24hour' }, timeZone: 'client' } }
    ]
  }
];

return tables.map(t => ({ json: t }));
